SELECT * FROM products

    status != 0

        AND MATCH(name, description) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)


        AND category_id = #{categoryId}


ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

mapper.update:
UPDATE products
category_id = #{categoryId}, name = #{name}, description = #{description}, tags = #{tags}, rating = #{rating}, sold = #{sold}, activity_label = #{activityLabel}, original_price = #{originalPrice}, price = #{price}, stock = #{stock}, status = #{status}, update_time = NOW()
WHERE id = #{id}

UPDATE product_skus
price = #{price}, stock = #{stock},
WHERE id = #{id}
